1	export function formatProbability(p: number): string {
2	  return `${(p * 100).toFixed(1)}%`;
3	}
4	
5	export function formatCurrency(n: number): string {
6	  if (Math.abs(n) >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
7	  if (Math.abs(n) >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
8	  return n.toFixed(2);
9	}
10	
11	export function truncateHash(hash: string, len = 8): string {
12	  if (hash.startsWith("sha256:")) return `sha256:${hash.slice(7, 7 + len)}…`;
13	  return hash.length > len ? `${hash.slice(0, len)}…` : hash;
14	}
15	
16	export function formatRelativeTime(iso: string): string {
17	  const diff = Date.now() - new Date(iso).getTime();
18	  const mins = Math.floor(diff / 60_000);
19	  if (mins < 1) return "just now";
20	  if (mins < 60) return `${mins}m ago`;
21	  const hours = Math.floor(mins / 60);
22	  if (hours < 24) return `${hours}h ago`;
23	  const days = Math.floor(hours / 24);
24	  return `${days}d ago`;
25	}
26	
27	export function timeUntil(iso: string): string {
28	  const diff = new Date(iso).getTime() - Date.now();
29	  if (diff <= 0) return "expired";
30	  const hours = Math.floor(diff / 3_600_000);
31	  const days = Math.floor(hours / 24);
32	  if (days > 0) return `${days}d ${hours % 24}h`;
33	  const mins = Math.floor((diff % 3_600_000) / 60_000);
34	  return `${hours}h ${mins}m`;
35	}
